// BLOCK 12.1: Crisis Signal Analyzer (Hardened v28.0)
// Analyzes incoming signals for crisis indicators
const item = $input.first();
const signal = item.json.body || item.json;

const CRISIS_INDICATORS = {
    model_exploit: ['prompt_injection_bypass', 'jailbreak_detected', 'adversarial_payload'],
    data_integrity: ['hash_mismatch', 'audit_chain_break', 'unauthorized_modification'],
    operational: ['flood_spike', 'latency_anomaly', 'error_rate_spike'],
    governance: ['unauthorized_override', 'constitution_violation', 'treaty_breach'],
    external: ['regulatory_halt', 'partner_bank_alert', 'cross_border_anomaly']
};

const detectedIndicators = [];
let maxSeverity = 0;

for (const [category, patterns] of Object.entries(CRISIS_INDICATORS)) {
    for (const pattern of patterns) {
        if (signal.indicator_type === pattern || signal.alert_type === pattern) {
            detectedIndicators.push({ category, pattern, severity: signal.severity || 2 });
            maxSeverity = Math.max(maxSeverity, signal.severity || 2);
        }
    }
}

const analysis = {
    signal_id: signal.signal_id || `SIG_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    source_system: signal.source_system || 'UNKNOWN',
    detected_indicators: detectedIndicators,
    indicator_count: detectedIndicators.length,
    max_severity: maxSeverity,
    raw_signal: signal,
    analysis_timestamp: new Date().toISOString()
};

return { json: analysis };

// BLOCK 12.2: Crisis Level Classifier (v28.0)
// Maps severity to crisis levels (0-5)
const item = $input.first();
const analysis = item.json;

const CRISIS_LEVELS = {
    0: { name: 'NORMAL', action: 'none', description: 'System operating normally' },
    1: { name: 'ELEVATED', action: 'monitor', description: 'Unusual activity detected, increased monitoring' },
    2: { name: 'WARNING', action: 'alert', description: 'Specific threat indicators present' },
    3: { name: 'CRITICAL', action: 'restrict', description: 'Active threat, restrict non-essential operations' },
    4: { name: 'EMERGENCY', action: 'halt', description: 'Severe threat, halt AI execution' },
    5: { name: 'BLACKBOX', action: 'seal', description: 'Cryptographic coma, full system seal' }
};

let crisisLevel = 0;
if (analysis.indicator_count === 0) {
    crisisLevel = 0;
} else if (analysis.max_severity <= 1) {
    crisisLevel = 1;
} else if (analysis.max_severity === 2) {
    crisisLevel = 2;
} else if (analysis.max_severity === 3) {
    crisisLevel = 3;
} else if (analysis.max_severity === 4) {
    crisisLevel = 4;
} else if (analysis.max_severity >= 5) {
    crisisLevel = 5;
}

const levelConfig = CRISIS_LEVELS[crisisLevel];

return {
    json: {
        ...analysis,
        crisis_level: crisisLevel,
        crisis_name: levelConfig.name,
        required_action: levelConfig.action,
        crisis_description: levelConfig.description,
        escalation_required: crisisLevel >= 3,
        __crisis_detected: crisisLevel > 0
    }
};

// BLOCK 12.4: Crisis Event Logger (v28.0)
// Logs crisis event to immutable audit trail
const item = $input.first();
const crisis = item.json;

return {
    json: {
        ...crisis,
        crisis_event: {
            event_id: `CRISIS_${crisis.signal_id}`,
            level: crisis.crisis_level,
            name: crisis.crisis_name,
            detected_at: crisis.analysis_timestamp,
            indicators: crisis.detected_indicators,
            logged_at: new Date().toISOString()
        },
        __logged: true
    }
};

// BLOCK 12.6: Crisis Response Builder (v28.0)
const item = $input.first();
const crisis = item.json;

return {
    json: {
        signal_id: crisis.signal_id,
        crisis_level: crisis.crisis_level,
        crisis_name: crisis.crisis_name,
        required_action: crisis.required_action,
        escalation_triggered: crisis.escalation_required,
        crisis_event_id: crisis.crisis_event.event_id,
        response_timestamp: new Date().toISOString(),
        next_steps: crisis.crisis_level >= 4 ? 'KILL_SWITCH_PROTOCOL_ACTIVATED' : 'MONITORING_ENHANCED'
    }
};

// BLOCK 12.8: Normal Operations Response (v28.0)
