// BLOCK 13.1: Authorization Validator (Hardened v28.0)
// Validates multi-party authorization for kill-switch
const crypto = require('crypto');
const item = $input.first();
const request = item.json.body || item.json;

const KILL_SWITCH_SECRET = $vars.KILL_SWITCH_SECRET || process.env.KILL_SWITCH_SECRET;
if (!KILL_SWITCH_SECRET) {
    throw new Error("CRITICAL: KILL_SWITCH_SECRET missing");
}

const requiredParties = ['compliance_officer', 'cto', 'legal_counsel'];
const providedSignatures = request.authorizations || [];

const validParties = providedSignatures.filter(auth => {
    if (!requiredParties.includes(auth.party)) return false;
    const expectedSig = crypto.createHmac('sha256', KILL_SWITCH_SECRET)
        .update(`${auth.party}:${request.kill_switch_id}:${auth.timestamp}`)
        .digest('hex');
    const authBuffer = Buffer.from(auth.signature);
    const expectedBuffer = Buffer.from(expectedSig);
    return authBuffer.length === expectedBuffer.length && 
           crypto.timingSafeEqual(authBuffer, expectedBuffer);
});

const authorizationSufficient = validParties.length >= 2;

return {
    json: {
        kill_switch_id: request.kill_switch_id || `KS_${Date.now()}`,
        requester: request.requester,
        valid_signatures: validParties.length,
        required_signatures: 2,
        authorization_sufficient: authorizationSufficient,
        authorized_parties: validParties.map(p => p.party),
        __authorization_valid: authorizationSufficient,
        __validation_timestamp: new Date().toISOString()
    }
};

// BLOCK 13.3: Kill-Switch Executor (v28.0)
// Executes emergency shutdown sequence
const item = $input.first();
const auth = item.json;

const shutdownSequence = {
    step_1: 'HALT_AI_EXECUTION',
    step_2: 'SEAL_MEMORY_CORE',
    step_3: 'SHRED_RUNTIME_KEYS',
    step_4: 'FREEZE_TRANSACTION_QUEUE',
    step_5: 'ACTIVATE_FORENSIC_MODE'
};

return {
    json: {
        ...auth,
        kill_switch: {
            activated_at: new Date().toISOString(),
            shutdown_sequence: shutdownSequence,
            status: 'EXECUTING',
            estimated_completion_ms: 500
        },
        system_state: 'ENTERING_BLACKBOX_MODE',
        __kill_switch_activated: true
    }
};

// BLOCK 13.5: Blackbox Sealer (v28.0)
// Creates cryptographic seal of system state
const crypto = require('crypto');
const item = $input.first();
const ks = item.json;

const blackboxSeal = {
    seal_id: `BLACKBOX_${Date.now()}`,
    kill_switch_id: ks.kill_switch_id,
    sealed_at: new Date().toISOString(),
    system_version: 'REVENANT_v28_0',
    memory_state: 'SEALED_READ_ONLY',
    keys_status: 'SHREDDED',
    transaction_queue: 'FROZEN',
    forensic_export_available: true
};

const sealHash = crypto.createHash('sha256')
    .update(JSON.stringify(blackboxSeal))
    .digest('hex');

return {
    json: {
        ...ks,
        blackbox_seal: {
            ...blackboxSeal,
            seal_hash: sealHash
        },
        __blackbox_active: true
    }
};

// BLOCK 13.6: Recovery Info Builder (v28.0)
const item = $input.first();
const ks = item.json;

return {
    json: {
        kill_switch_id: ks.kill_switch_id,
        status: 'BLACKBOX_MODE_ACTIVE',
        activated_at: ks.kill_switch.activated_at,
        blackbox_seal_id: ks.blackbox_seal.seal_id,
        seal_hash: ks.blackbox_seal.seal_hash,
        recovery_requirements: {
            multi_party_signatures: true,
            regulator_approval: true,
            integrity_verification: true,
            hash_chain_continuity_check: true
        },
        forensic_export_endpoint: '/forensic-export',
        response_timestamp: new Date().toISOString()
    }
};

// ⚠️ BLOCK 13.ERROR: Authorization Failed (v28.0)
const item = $input.first();
const auth = item.json;

return {
    json: {
        kill_switch_id: auth.kill_switch_id,
        status: 'REJECTED',
        rejection_reason: 'INSUFFICIENT_AUTHORIZATION',
        valid_signatures: auth.valid_signatures,
        required_signatures: auth.required_signatures,
        missing_parties: ['compliance_officer', 'cto', 'legal_counsel'].filter(p => 
            !auth.authorized_parties?.includes(p)
        ),
        rejected_at: new Date().toISOString()
    }
};
